  "exercises": [
    {
      "words": ["Je", "veux", "un", "pains", "."],
      "translation": "Ich möchte ein Brot.",
      "explanation": "Bei A1-Sätzen folgt die Wortstellung SVO: Subjekt (Je), Verb (veux), Objekt (un pains). Das Komma wird nicht verwendet, der Punkt steht am Ende."
    },
    {
      "words": ["Tu", "as", "un", "chien", "."],
      "translation": "Du hast einen Hund.",
      "explanation": "Das Subjekt kommt zuerst, dann das Verb 'avoir' (as), gefolgt vom direkten Objekt. Bei männlichen Nomen ist der Artikel 'un'."
    },
    {
      "words": ["Elle", "aime", "l'eau", "."],
      "translation": "Sie mag Wasser.",
      "explanation": "Subjekt (Elle), Verb (aime), Objekt (l'eau). Der Akkusativ wird durch den Artikel 'l'' für weibliche Wörter gebildet."
    },
    {
      "words": ["Nous", "voulons", "deux", "eaux", "."],
      "translation": "Wir wollen zwei Wasser.",
      "explanation": "Subjekt (Nous), Verb (voulons), Zahlwort (deux) und Nomen (eaux). Bei unzählbaren Substantiven wie 'eau' wird der Plural mit einem S gebildet."
    },
    {
      "words": ["Il", "a", "une", "maison", "."],
      "translation": "Er hat ein Haus.",
      "explanation": "Subjekt (Il), Verb (a), Artikel (une) für weibliche Nomen, dann das Substantiv (maison). Die Wortstellung ist immer SVO."
    }
  ]
}
